    name: "everything",
    files: [
      "docs/x.md",
      "src/api/v1/handler.ts",
      "tests/foo.spec.ts",
      ".github/workflows/build.yml",
      "package.json",
    ],
    // documentation(1), api(2), tests(3), ci(4); package.json is excluded by config rule? No — rules.json excludes .github/** from "config" not *.json. So config(5) also matches.
