  // runs `git clone` of the working dir and we don't want to pollute the
  // real repo with fixture files.
  tempRepo = mkdtempSync(join(tmpdir(), "pr-label-assigner-"));
  // Copy everything from ROOT except node_modules, .git, act-result.txt.
  cpSync(ROOT, tempRepo, {
    recursive: true,
    filter: (src) => {
      const rel = src.slice(ROOT.length).replace(/^\//, "");
      if (rel === "" ) return true;
      if (rel.startsWith("node_modules")) return false;
      if (rel.startsWith(".git/")) return false;
      if (rel === ".git") return false;
      if (rel === "act-result.txt") return false;
      return true;
    },
  });
  // Initialize a fresh git repo so `actions/checkout` (which act intercepts)
  // and `git ls-files` work.
  const gitInit = (args: string[]) =>
    spawnSync("git", args, { cwd: tempRepo, encoding: "utf8" });
  gitInit(["init", "-q", "-b", "main"]);
  gitInit(["config", "user.email", "test@example.com"]);
