interface ActRunResult {
  status: number;
  stdout: string;
  stderr: string;
}

/**
 * Run `act push --rm` once with FIXTURE_FILES pointing at the given file.
 * Returns combined output + exit status.
 */
function runActOnce(scenario: Scenario): ActRunResult {
  const fixturePath = join(tempRepo, "fixture.txt");
  writeFileSync(fixturePath, scenario.files.join("\n") + "\n");
  // Pass the fixture path as a *relative* path inside the runner workspace.
  // act mounts the project at /github/workspace/<project-dir>, so a relative
  // path resolves fine since the workflow `working-directory` defaults to
  // that mount.
  const envFile = join(tempRepo, ".act.env");
  writeFileSync(envFile, `FIXTURE_FILES=fixture.txt\n`);

  const result = spawnSync(
    "act",
    [
      "push",
      "--rm",
      "--env-file", envFile,
      "-W", ".github/workflows/pr-label-assigner.yml",
    ],
    { cwd: tempRepo, encoding: "utf8", maxBuffer: 50 * 1024 * 1024 },
  );
  return {
    status: result.status ?? -1,
    stdout: result.stdout ?? "",
    stderr: result.stderr ?? "",
  };
}

/**
 * Append a delimited block to act-result.txt with the captured output.
 */
function appendActResult(scenario: Scenario, run: ActRunResult): void {
  const block =
    `\n========== CASE: ${scenario.name} ==========\n` +
    `expected: ${JSON.stringify(scenario.expected)}\n` +
    `exit: ${run.status}\n` +
    `--- stdout ---\n${run.stdout}\n` +
    `--- stderr ---\n${run.stderr}\n` +
    `========== END CASE: ${scenario.name} ==========\n`;
  appendFileSync(ACT_RESULT_FILE, block);
}

/**
 * Pull the labels block out of act stdout. Each run prints
 *   ----- LABELS-BEGIN -----\n<labels>\n----- LABELS-END -----
 * inside the assign step. Whitespace lines are dropped.
 */
function extractLabels(actStdout: string): string[] {
  const m = actStdout.match(/----- LABELS-BEGIN -----([\s\S]*?)----- LABELS-END -----/);
  if (!m) return [];
  return m[1]!
    .split("\n")
    .map((s) => s.replace(/^\|\s?/, "").trim())  // act prefixes lines with "| "
    .filter((s) => s.length > 0);
}

describe("act end-to-end", () => {
  for (const scenario of SCENARIOS) {
    actTest(`scenario: ${scenario.name}`, () => {
      const run = runActOnce(scenario);
      appendActResult(scenario, run);

      // Persist the per-case output even if assertions below fail, so
      // act-result.txt always reflects the latest attempt.
      expect(run.status).toBe(0);
      // act prints "Job succeeded" once per job; we have two jobs.
      const succeeded = (run.stdout.match(/Job succeeded/g) || []).length;
      expect(succeeded).toBeGreaterThanOrEqual(2);

      const labels = extractLabels(run.stdout);
      expect(labels).toEqual(scenario.expected);
    }, 600_000);
  }
});

