interface ActRunResult {
  status: number;
  stdout: string;
  stderr: string;
}

/**
 * Run `act push --rm` once with FIXTURE_FILES pointing at the given file.
 * Returns combined output + exit status.
 */
function runActOnce(scenario: Scenario): ActRunResult {
  const fixturePath = join(tempRepo, "fixture.txt");
